import React, { useState } from 'react';
import { Button, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { AccountingPeriodDto } from '../../../services/kt/models';
import { formatDateTimeLocal } from '../../../utils/formatters';
import erp from '../../../styles/erpPage.module.css';

const KyKeToanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [items, setItems] = useState<AccountingPeriodDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [acting, setActing] = useState<string | null>(null);

  const load = () => {
    setLoading(true);
    ktService.getPeriods()
      .then(setItems)
      .catch(err => dispatch(addToast({ message: err?.message ?? 'Lỗi tải kỳ', type: 'error' })))
      .finally(() => setLoading(false));
  };

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  const handleClose = async (id: string) => {
    setActing(id);
    try {
      await ktService.closePeriod(id);
      dispatch(addToast({ message: 'Đóng kỳ thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi đóng kỳ', type: 'error' }));
    } finally {
      setActing(null);
    }
  };

  const handleLock = async (id: string) => {
    setActing(id);
    try {
      await ktService.lockPeriod(id);
      dispatch(addToast({ message: 'Khóa kỳ thành công', type: 'success' }));
      load();
    } catch (e: unknown) {
      dispatch(addToast({ message: e instanceof Error ? e.message : 'Lỗi khóa kỳ', type: 'error' }));
    } finally {
      setActing(null);
    }
  };

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-calendar-alt" /> Kỳ kế toán</h1></div>
      </div>
      <div className={erp.tableCard}>
        {loading ? <div className={erp.loading}>Đang tải...</div> : (
          <div className={erp.tableWrapper}>
            <table className={erp.table}>
              <thead><tr><th>Tháng</th><th>Năm</th><th>Trạng thái</th><th>Đóng lúc</th><th>Khóa lúc</th><th /></tr></thead>
              <tbody>{items.map(p => (
                <tr key={p.id}>
                  <td>{p.month}</td>
                  <td>{p.year}</td>
                  <td><span className={erp.tagDefault}>{p.status}</span></td>
                  <td>{p.closedAt ? formatDateTimeLocal(p.closedAt) : '—'}</td>
                  <td>{p.lockedAt ? formatDateTimeLocal(p.lockedAt) : '—'}</td>
                  <td className={erp.colActions}>
                    {p.status === 'Open' && <Button size="sm" onClick={() => handleClose(p.id)} loading={acting === p.id}>Đóng</Button>}
                    {p.status === 'Closed' && <Button size="sm" variant="secondary" onClick={() => handleLock(p.id)} loading={acting === p.id}>Khóa</Button>}
                  </td>
                </tr>
              ))}</tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default KyKeToanPage;
