export const formatDateLocal = (iso: string) =>
  iso ? new Date(iso).toLocaleDateString('vi-VN') : '';

export const formatDateTimeLocal = (iso: string) =>
  iso ? new Date(iso).toLocaleString('vi-VN') : '';

const hasFraction = (n: number) => Math.abs(n % 1) > 1e-9;

/** Tiền — ###.###.###.##0 (dấu chấm phân nghìn, không thập phân) */
export function formatMoney(value: number | null | undefined): string {
  if (value == null) return '0';
  const n = Math.round(Number(value));
  if (!Number.isFinite(n)) return '0';
  return n.toLocaleString('de-DE', { maximumFractionDigits: 0 });
}

/** Tiền + suffix đ */
export function formatMoneyVnd(value: number | null | undefined): string {
  if (value == null) return '—';
  return `${formatMoney(value)} đ`;
}

/** @deprecated use formatMoneyVnd */
export const formatVnd = formatMoneyVnd;

/**
 * Số lượng — # ### ### ### ##0,### (dấu cách nghìn, phẩy thập phân).
 * Không có phần thập phân trong value → chỉ hiển thị phần nguyên.
 */
export function formatQuantity(
  value: number | null | undefined,
  maxDecimals = 3,
): string {
  if (value == null) return '0';
  const n = Number(value);
  if (!Number.isFinite(n)) return '0';

  if (!hasFraction(n)) {
    return Math.round(n)
      .toLocaleString('vi-VN', { maximumFractionDigits: 0 })
      .replace(/\./g, ' ');
  }

  const formatted = n.toLocaleString('vi-VN', {
    minimumFractionDigits: 1,
    maximumFractionDigits: maxDecimals,
  });
  const commaIdx = formatted.lastIndexOf(',');
  if (commaIdx < 0) {
    return formatted.replace(/\./g, ' ');
  }
  const intPart = formatted.slice(0, commaIdx).replace(/\./g, ' ');
  const decPart = formatted.slice(commaIdx + 1);
  return `${intPart},${decPart}`;
}

/** Parse tiền: bỏ dấu chấm nghìn */
export function parseMoneyInput(raw: string): number {
  const cleaned = raw.replace(/\s/g, '').replace(/\./g, '').replace(/[^\d-]/g, '');
  const n = parseInt(cleaned, 10);
  return Number.isFinite(n) ? n : 0;
}

/** Parse số lượng: bỏ space, đổi , → . */
export function parseQuantityInput(raw: string): number {
  const trimmed = raw.trim();
  if (!trimmed) return 0;
  const cleaned = trimmed.replace(/\s/g, '').replace(',', '.');
  const n = parseFloat(cleaned);
  return Number.isFinite(n) ? n : 0;
}

/** @deprecated dùng parseMoneyInput / parseQuantityInput */
export function parseLocaleNumber(raw: string): number {
  return parseQuantityInput(raw);
}
